+
+const ALL_CLASSES: LesionClass[] = ["akiec", "bcc", "bkl", "df", "mel", "nv", "vasc"];
+
+/** Base skin tones per Fitzpatrick type (RGB) */
+const SKIN_TONES: Record<FitzpatrickType, [number, number, number]> = {
+	I: [255, 224, 196],
+	II: [240, 200, 166],
+	III: [210, 170, 130],
