+		// Location adjustment
+		if (localization) {
+			const normalizedLoc = normalizeLocation(localization);
+			const locFactors = HAM10000_KNOWLEDGE.riskFactors.location[cls];
+			multiplier *= locFactors[normalizedLoc] ?? 1.0;
+		}
