+	// Re-normalize to sum to 1
+	const total = Object.values(adjusted).reduce((a, b) => a + b, 0);
+	if (total > 0) {
+		for (const cls of classes) {
+			adjusted[cls] = adjusted[cls] / total;
+		}
+	}
