+	{ name: "ssn", regex: /\b\d{3}-\d{2}-\d{4}\b/g },
+	{ name: "date_of_birth", regex: /\b(0[1-9]|1[0-2])\/(0[1-9]|[12]\d|3[01])\/(19|20)\d{2}\b/g },
